SELECT id, term, meaning, field_name, major_name, minor_name, status, wrong_count, last_reviewed_on, created_at
FROM words


        (term LIKE CONCAT('%', #{keyword}, '%') OR meaning LIKE CONCAT('%', #{keyword}, '%'))


        AND minor_name = #{minorName}


        AND status = #{status}


ORDER BY wrong_count DESC, term ASC

